import { useEffect, useRef } from 'react';
import './search_bar.scss';

export interface BreadcrumbItem {
  label: string;
  onBack: () => void;
}

interface SearchBarProps {
  value: string;
  onChange: (value: string) => void;
  placeholder?: string;
  activeDescendantId?: string;
  breadcrumbs?: BreadcrumbItem[];
}

export function SearchBar({
  value,
  onChange,
  placeholder = 'Search...',
  activeDescendantId,
  breadcrumbs,
}: SearchBarProps) {
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  useEffect(() => {
    if (!breadcrumbs?.length) return;

    function handleKeyDown(e: KeyboardEvent) {
      if (e.key === 'Escape') {
        e.preventDefault();
        if (value) {
          onChange('');
        } else {
          breadcrumbs![breadcrumbs!.length - 1].onBack();
        }
      }
    }

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [breadcrumbs, onChange, value]);

  return (
    <div className="search-bar" role="search">
      <svg
        className="search-bar__icon"
        width="16"
        height="16"
        viewBox="0 0 16 16"
        fill="none"
        xmlns="http://www.w3.org/2000/svg"
      >
        <circle cx="7" cy="7" r="4.5" stroke="currentColor" strokeWidth="1.5" />
        <line
          x1="10.5"
          y1="10.5"
          x2="14"
          y2="14"
          stroke="currentColor"
          strokeWidth="1.5"
          strokeLinecap="round"
        />
      </svg>
      {breadcrumbs && breadcrumbs.length > 0 && (
        <div className="search-bar__breadcrumbs">
          {breadcrumbs.map((crumb, i) => (
            <button
              key={i}
              className="search-bar__breadcrumb"
              onClick={crumb.onBack}
              type="button"
              aria-label={`Back to ${crumb.label}`}
            >
              {crumb.label}
              {i < breadcrumbs.length - 1 && (
                <svg
                  className="search-bar__breadcrumb-chevron"
                  width="8"
                  height="8"
                  viewBox="0 0 8 8"
                  fill="none"
                >
                  <path
                    d="M2.5 1.5L5.5 4L2.5 6.5"
                    stroke="currentColor"
                    strokeWidth="1.2"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                  />
                </svg>
              )}
            </button>
          ))}
        </div>
      )}
      <input
        ref={inputRef}
        className="search-bar__input"
        type="text"
        value={value}
        onChange={e => onChange(e.target.value)}
        placeholder={placeholder}
        role="combobox"
        aria-expanded={true}
        aria-controls="command-list"
        aria-activedescendant={activeDescendantId}
        aria-label="Search commands"
        spellCheck={false}
        autoComplete="off"
      />
    </div>
  );
}

